files.content:
[data-slot="switch-root"] {
  display: inline-flex;
  max-inline-size: 100%;
}

.mrg-switch {
  align-items: center;
  appearance: none;
  background: transparent;
  border: 0;
  color: var(--mrg-semantic-color-foreground-primary);
  cursor: pointer;
  display: inline-flex;
  font: inherit;
  gap: var(--mrg-semantic-space-inline-sm);
  max-inline-size: 100%;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  padding: 0;
  text-align: start;
}

.mrg-switch [data-slot="switch-track"] {
  align-items: center;
  background: var(--mrg-semantic-color-background-surface-sunken);
  border: var(--mrg-semantic-border-width-strong) solid var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  display: flex;
  flex: 0 0 auto;
  inline-size: 2.75rem;
  min-block-size: 1.5rem;
  padding: 0.125rem;
}

.mrg-switch [data-slot="switch-thumb"] {
  background: var(--mrg-semantic-color-foreground-primary);
  border-radius: var(--mrg-semantic-radius-pill);
  block-size: 1rem;
  inline-size: 1rem;
  transform: translateX(0);
  transition: transform var(--mrg-semantic-motion-duration-transition)
    var(--mrg-semantic-motion-easing-standard);
}

.mrg-switch[data-state="on"] [data-slot="switch-track"] {
  background: var(--mrg-semantic-color-selection-background);
  border-color: var(--mrg-semantic-color-selection-border);
}

.mrg-switch[data-state="on"] [data-slot="switch-thumb"] {
  background: var(--mrg-semantic-color-selection-foreground);
  transform: translateX(1.25rem);
}

[dir="rtl"] .mrg-switch[data-state="on"] [data-slot="switch-thumb"],
.mrg-switch[dir="rtl"][data-state="on"] [data-slot="switch-thumb"] {
  transform: translateX(-1.25rem);
}

.mrg-switch [data-slot="switch-content"] {
  display: grid;
  gap: var(--mrg-semantic-space-stack-xs);
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-switch [data-slot="switch-label"] {
  font-weight: var(--mrg-semantic-font-weight-label);
}

.mrg-switch [data-slot="switch-state-label"] {
  color: var(--mrg-semantic-color-foreground-muted);
  font-size: var(--mrg-semantic-font-size-label);
}

.mrg-switch:focus-visible {
  box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}

.mrg-switch:disabled {
  color: var(--mrg-semantic-color-foreground-disabled);
  cursor: not-allowed;
}

.mrg-switch:disabled [data-slot="switch-track"] {
  border-color: var(--mrg-semantic-color-border-disabled);
}

@media (prefers-reduced-motion: reduce) {
  .mrg-switch [data-slot="switch-thumb"] {
    transition: none;
  }
}

@media (forced-colors: active) {
  .mrg-switch:focus-visible {
    box-shadow: none;
    outline-color: Highlight;
  }

  .mrg-switch [data-slot="switch-track"] {
    background: ButtonFace;
    border-color: ButtonText;
  }

  .mrg-switch [data-slot="switch-thumb"] {
    background: ButtonText;
  }

  .mrg-switch[data-state="on"] [data-slot="switch-track"] {
    background: Highlight;
    border-color: Highlight;
  }

  .mrg-switch[data-state="on"] [data-slot="switch-thumb"] {
    background: HighlightText;
  }
}

"use client";

import {
  forwardRef,
  Fragment,
  useCallback,
  useEffect,
  useRef,
  useState,
  isValidElement,
  type ButtonHTMLAttributes,
  type ForwardedRef,
  type MouseEventHandler,
  type ReactNode,
} from "react";

import { useMergoraMessage } from "../provider/index";
import "./switch.css";

export interface SwitchProps extends Omit<
  ButtonHTMLAttributes<HTMLButtonElement>,
  "aria-checked" | "children" | "defaultValue" | "name" | "role" | "type" | "value"
> {
  /** Non-empty visible setting label that supplies the switch accessible name. */
  readonly children: ReactNode;
  /** Initial boolean state for uncontrolled use; defaults to false. */
  readonly defaultValue?: boolean;
  /** Optional native form name enabling hidden enum serialization. */
  readonly name?: string;
  /** Localized visible off-state text hidden from accessibility APIs. */
  readonly offLabel?: ReactNode;
  /** Hidden form value serialized while off; defaults to `off`. */
  readonly offValue?: string;
  /** Localized visible on-state text hidden from accessibility APIs. */
  readonly onLabel?: ReactNode;
  /** Hidden form value serialized while on; defaults to `on`. */
  readonly onValue?: string;
  /** Receives proposed controlled or committed uncontrolled state changes. */
  readonly onValueChange?: (value: boolean) => void;
  /** Controlled boolean state; changes are proposed through `onValueChange`. */
  readonly value?: boolean;
}

function setForwardedRef<T>(ref: ForwardedRef<T>, value: T | null): void {
  if (typeof ref === "function") ref(value);
  else if (ref !== null) ref.current = value;
}

interface ProcessLike {
  readonly env?: { readonly NODE_ENV?: string };
}

function isDevelopmentRuntime(): boolean {
  const viteProduction = (
    import.meta as ImportMeta & { readonly env?: { readonly PROD?: boolean } }
  ).env?.PROD;
  const runtime = globalThis as typeof globalThis & { readonly process?: ProcessLike };
  return viteProduction !== true && runtime.process?.env?.NODE_ENV !== "production";
}

function hasAccessibleContent(value: ReactNode): boolean {
  if (value === null || value === undefined || typeof value === "boolean") return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.some(hasAccessibleContent);
  if (isValidElement<{ readonly children?: ReactNode }>(value)) {
    if (value.type === Fragment) return hasAccessibleContent(value.props.children);
    return typeof value.type === "string" ? hasAccessibleContent(value.props.children) : true;
  }
  return true;
}

function validateOptionalNonBlank(value: string | undefined, name: string): void {
  if (value !== undefined && value.trim().length === 0) {
    throw new RangeError(`Mergora Switch ${name} must not be empty or whitespace-only.`);
  }
}

export const Switch = forwardRef<HTMLButtonElement, SwitchProps>(function Switch(
  {
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    children,
    className,
    defaultValue = false,
    disabled = false,
    form,
    name,
    offLabel: offLabelProp,
    offValue = "off",
    onClick,
    onLabel: onLabelProp,
    onValue = "on",
    onValueChange,
    value,
    ...nativeProps
  },
  forwardedRef,
) {
  const defaultOffLabel = useMergoraMessage("switch.off", "Off");
  const defaultOnLabel = useMergoraMessage("switch.on", "On");
  const offLabel = offLabelProp === undefined ? defaultOffLabel : offLabelProp;
  const onLabel = onLabelProp === undefined ? defaultOnLabel : onLabelProp;
  validateOptionalNonBlank(name, "name");
  validateOptionalNonBlank(form, "form");
  if (onValue === offValue) {
    throw new RangeError("Mergora Switch onValue and offValue must be distinct.");
  }
  const buttonRef = useRef<HTMLButtonElement | null>(null);
  const controlled = value !== undefined;
  const [uncontrolledValue, setUncontrolledValue] = useState(defaultValue);
  const resolvedValue = value ?? uncontrolledValue;

  useEffect(() => {
    const ownerForm = buttonRef.current?.form;
    if (ownerForm === null || ownerForm === undefined) return;
    let timer: ReturnType<typeof setTimeout> | undefined;
    const handleReset = () => {
      timer = setTimeout(() => {
        if (!controlled) setUncontrolledValue(defaultValue);
      }, 0);
    };
    ownerForm.addEventListener("reset", handleReset);
    return () => {
      ownerForm.removeEventListener("reset", handleReset);
      if (timer !== undefined) clearTimeout(timer);
    };
  }, [controlled, defaultValue, form]);

  useEffect(() => {
    if (
      isDevelopmentRuntime() &&
      !hasAccessibleContent(children) &&
      (ariaLabel === undefined || ariaLabel.trim().length === 0) &&
      (ariaLabelledBy === undefined || ariaLabelledBy.trim().length === 0)
    ) {
      console.warn("Mergora Switch requires children, aria-label, or aria-labelledby.");
    }
    if (isDevelopmentRuntime() && !hasAccessibleContent(onLabel)) {
      console.warn("Mergora Switch requires a non-empty visible onLabel.");
    }
    if (isDevelopmentRuntime() && !hasAccessibleContent(offLabel)) {
      console.warn("Mergora Switch requires a non-empty visible offLabel.");
    }
  }, [ariaLabel, ariaLabelledBy, children, offLabel, onLabel]);

  const assignButton = useCallback(
    (node: HTMLButtonElement | null) => {
      buttonRef.current = node;
      setForwardedRef(forwardedRef, node);
    },
    [forwardedRef],
  );
  const handleClick: MouseEventHandler<HTMLButtonElement> = (event) => {
    onClick?.(event);
    if (event.defaultPrevented) return;
    const next = !resolvedValue;
    if (!controlled) setUncontrolledValue(next);
    onValueChange?.(next);
  };

  return (
    <span data-disabled={disabled || undefined} data-slot="switch-root">
      <button
        {...nativeProps}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        aria-checked={resolvedValue}
        className={className === undefined ? "mrg-switch" : `mrg-switch ${className}`}
        data-slot="switch"
        data-state={resolvedValue ? "on" : "off"}
        disabled={disabled}
        form={form}
        onClick={handleClick}
        ref={assignButton}
        role="switch"
        type="button"
      >
        <span aria-hidden="true" data-slot="switch-track">
          <span data-slot="switch-thumb" />
        </span>
        <span data-slot="switch-content">
          <span data-slot="switch-label">{children}</span>
          <span aria-hidden="true" data-slot="switch-state-label">
            {resolvedValue ? onLabel : offLabel}
          </span>
        </span>
      </button>
      {name === undefined ? null : (
        <input
          data-slot="switch-form-value"
          disabled={disabled}
          form={form}
          name={name}
          readOnly
          type="hidden"
          value={resolvedValue ? onValue : offValue}
        />
      )}
    </span>
  );
});

Switch.displayName = "Switch";
